// Amounts in the PDF use "Rs" (the built-in PDF font has no ₹ glyph).
const pdfInr = (n) => "Rs " + Number(n || 0).toLocaleString("en-IN");

// Build and download a clean PDF copy of a bill. jsPDF is loaded on demand.
async function downloadBillPdf(bill, shop) {
  const { jsPDF } = await import("jspdf");
  const left = 40, right = 555, width = right - left;
  let y = 50;
  doc.setFont("helvetica", "bold"); doc.setFontSize(18);
  doc.text(shop.shopName || "Hyrocks Crackers", left, y); y += 20;
  doc.setFont("helvetica", "normal"); doc.setFontSize(10); doc.setTextColor(90);
  if (shop.address) { const a = doc.splitTextToSize(shop.address, width); doc.text(a, left, y); y += a.length * 12; }
  if (shop.phone) { doc.text("Phone: " + shop.phone, left, y); y += 14; }
  doc.setTextColor(0); y += 6;
  doc.setDrawColor(200); doc.line(left, y, right, y); y += 18;
  doc.setFontSize(11); doc.setFont("helvetica", "bold");
  doc.text("BILL " + (bill.billNo || ""), left, y);
  doc.setFont("helvetica", "normal");
  doc.text(new Date(bill.createdAt).toLocaleString("en-IN"), right, y, { align: "right" }); y += 16;
  if (bill.customerName || bill.customerMobile) {
    doc.text("Customer: " + [bill.customerName, bill.customerMobile].filter(Boolean).join("  "), left, y); y += 14;
  }
  if (bill.paymentMode) { doc.text("Payment: " + (bill.paymentMode === "online" ? "Online" : "Cash"), left, y); y += 14; }
  y += 4; doc.setDrawColor(220); doc.line(left, y, right, y); y += 16;
  doc.setFont("helvetica", "bold"); doc.setFontSize(10);
  doc.text("Item", left, y); doc.text("Qty", right - 140, y, { align: "right" }); doc.text("Amount", right, y, { align: "right" }); y += 6;
  doc.setDrawColor(220); doc.line(left, y, right, y); y += 16;
  doc.setFont("helvetica", "normal");
  (bill.lines || []).forEach((l) => {
    const nm = doc.splitTextToSize(l.name || "", width - 170);
    doc.text(nm, left, y);
    doc.text(String(l.qty), right - 140, y, { align: "right" });
    doc.text(pdfInr(l.amount != null ? l.amount : l.price * l.qty), right, y, { align: "right" });
    y += Math.max(nm.length * 12, 14);
  });
  y += 4; doc.setDrawColor(220); doc.line(left, y, right, y); y += 16;
  const row = (label, val, bold) => {
    doc.setFont("helvetica", bold ? "bold" : "normal"); doc.setFontSize(bold ? 12 : 10);
    doc.text(label, right - 140, y, { align: "right" });
    doc.text(val, right, y, { align: "right" });
    y += bold ? 18 : 14;
  };
  row("Subtotal", pdfInr(bill.subtotal));
  if (bill.discountAmount > 0) row("Discount", "- " + pdfInr(bill.discountAmount));
  row("TOTAL", pdfInr(bill.total), true);
  y += 10; doc.setFont("helvetica", "normal"); doc.setFontSize(9); doc.setTextColor(120);
  if (bill.billedBy) { doc.text("Billed by: " + bill.billedBy, left, y); y += 13; }
  doc.text("Thank you! Have a safe & happy celebration.", left, y);
  doc.save("Bill-" + (bill.billNo || "hyrocks") + ".pdf");
}

const LOGO_DATA_URI = "data:image/jpeg;base64,";

/* ------------------------------------------------------------------ */
/* Small id generator for brand-new records before the server assigns */
/* ------------------------------------------------------------------ */
const uid = () => Math.random().toString(36).slice(2, 10);

/* ------------------------------------------------------------------ */
/* Helpers                                                            */
/* ------------------------------------------------------------------ */
const inr = (n) => "₹" + Number(n || 0).toLocaleString("en-IN");

// Mirror of the database password rule, for instant feedback.
function pwError(p) {
  if (!p || p.length < 8) return "Use at least 8 characters";
  if (!/[A-Z]/.test(p)) return "Add at least one CAPITAL letter (A-Z)";
  if (!/[a-z]/.test(p)) return "Add at least one small letter (a-z)";
  if (!/[0-9]/.test(p)) return "Add at least one number (0-9)";
  if (!/[^A-Za-z0-9]/.test(p)) return "Add at least one symbol (e.g. ! @ # $)";
  return "";
}

function fmtDateTime(iso) {
  const d = new Date(iso);
  return d.toLocaleString("en-IN", {
    day: "2-digit", month: "short", year: "numeric",
    hour: "2-digit", minute: "2-digit",
  });
}

function startOfToday() {
  const d = new Date();
  d.setHours(0, 0, 0, 0);
  return d.getTime();
}

function sanitizePhone(raw) {
  let d = (raw || "").replace(/\D/g, "");
  if (d.startsWith("0")) d = d.slice(1);
  if (d.length === 10) d = "91" + d;
  return d;
}

function billNoStr(n) { return "HRC-" + String(n).padStart(4, "0"); }

function receiptText(bill, config) {
  const lines = bill.lines
    .map((l) => `${l.name} x${l.qty}  =  ${inr(l.amount)}`)
    .join("\n");
  let t = `*${config.shopName}*\n`;
  if (config.address) t += `${config.address}\n`;
  if (config.phone) t += `Ph: ${config.phone}\n`;
  t += `------------------------------\n`;
  t += `Bill: ${bill.billNo}\n${fmtDateTime(bill.createdAt)}\n`;
  if (bill.customerName) t += `Customer: ${bill.customerName}\n`;
  t += `------------------------------\n${lines}\n------------------------------\n`;
  t += `Subtotal: ${inr(bill.subtotal)}\n`;
  if (bill.discountAmount > 0) t += `Discount: -${inr(bill.discountAmount)}\n`;
  t += `*TOTAL: ${inr(bill.total)}*\n`;
  t += `------------------------------\nBilled by: ${bill.billedBy}\nThank you! Have a safe & happy celebration 🎆`;
  const origin = (typeof window !== "undefined" && window.location && window.location.origin) ? window.location.origin : "";
  if (origin && bill.id) t += `\n\n📄 View / download your bill & rate us:\n${origin}/?bill=${bill.id}`;
  return t;
}

/* ================================================================== */
/* Public bill page (opened from the WhatsApp link, no login)         */
/* ================================================================== */
export function PublicBill() {
  const billId = new URLSearchParams(window.location.search).get("bill") || "";
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState(null);     // { bill, shop }
  const [rating, setRating] = useState(0);
  const [hover, setHover] = useState(0);
  const [comment, setComment] = useState("");
  const [busy, setBusy] = useState(false);
  const [done, setDone] = useState(false);
  const [err, setErr] = useState("");
  const [pdfBusy, setPdfBusy] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const r = await rpc("get_bill_public", { p_id: billId });
        if (r && r.ok) setData({ bill: r.bill, shop: r.shop });
      } catch (e) { /* not found */ }
      setLoading(false);
    })();
  }, []);

  const submit = async () => {
    if (rating < 1) { setErr("Please tap a star rating"); return; }
    setBusy(true); setErr("");
    try {
      const b = data ? data.bill : {};
      const r = await rpc("submit_feedback", {
        p_bill_no: b.billNo || "", p_rating: rating, p_comment: comment.trim(),
        p_name: b.customerName || "", p_mobile: b.customerMobile || "",
      });
      if (!r || !r.ok) { setErr((r && r.error) || "Could not submit"); setBusy(false); return; }
      setDone(true);
    } catch (e) { setErr(e.message || "Could not submit. Please try again."); }
    setBusy(false);
  };

  const Card = ({ children }) => (
    <div className="min-h-screen bg-slate-50 flex items-start justify-center p-4">
      <div className="w-full max-w-md mt-8">
        <div className="flex flex-col items-center mb-5">
          <img src={LOGO_DATA_URI} alt="" className="w-16 h-16 rounded-2xl object-cover shadow mb-2" />
          <h1 className="text-xl font-bold text-gray-900">{data?.shop?.shopName || "Hyrocks Crackers"}</h1>
        </div>
        {children}
        <p className="text-center text-[11px] text-gray-400 mt-4">Hyrocks Crackers · F Squad Enterprises</p>
      </div>
    </div>
  );

  if (loading) return <Card><div className="bg-white rounded-2xl border border-gray-200 p-8 text-center text-gray-400 text-sm">Loading your bill…</div></Card>;
  if (!data) return <Card><div className="bg-white rounded-2xl border border-gray-200 p-8 text-center text-gray-500 text-sm">Sorry, this bill link is invalid or has expired.</div></Card>;

  const { bill, shop } = data;
  return (
    <Card>
      {/* bill */}
      <div className="bg-white rounded-2xl border border-gray-200 p-5 font-mono text-[13px] text-gray-900">
        <div className="flex justify-between text-xs text-gray-500">
          <span>{bill.billNo}</span>
          <span>{new Date(bill.createdAt).toLocaleString("en-IN")}</span>
        </div>
        {(bill.customerName || bill.customerMobile) && (
          <p className="text-xs text-gray-500 mt-1">{[bill.customerName, bill.customerMobile].filter(Boolean).join(" · ")}</p>
        )}
        {bill.paymentMode && <p className="text-xs text-gray-500">Payment: {bill.paymentMode === "online" ? "Online" : "Cash"}</p>}
        <div className="border-t border-dashed border-gray-300 my-2" />
        {(bill.lines || []).map((l, i) => (
          <div key={i} className="flex justify-between">
            <span className="pr-2">{l.name} ×{l.qty}</span>
            <span>{inr(l.amount != null ? l.amount : l.price * l.qty)}</span>
          </div>
        ))}
        <div className="border-t border-dashed border-gray-300 my-2" />
        <div className="flex justify-between text-xs"><span>Subtotal</span><span>{inr(bill.subtotal)}</span></div>
        {bill.discountAmount > 0 && <div className="flex justify-between text-xs"><span>Discount</span><span>- {inr(bill.discountAmount)}</span></div>}
        <div className="flex justify-between font-bold mt-1"><span>Total</span><span>{inr(bill.total)}</span></div>
      </div>

      <button onClick={async () => { setPdfBusy(true); try { await downloadBillPdf(bill, shop); } catch (e) {} setPdfBusy(false); }}
        disabled={pdfBusy}
        className="w-full mt-3 py-3 rounded-xl bg-indigo-900 text-white font-semibold flex items-center justify-center gap-2 disabled:opacity-60">
        <Printer className="w-4 h-4" /> {pdfBusy ? "Preparing…" : "Download PDF copy"}
      </button>

      {/* feedback */}
      <div className="bg-white rounded-2xl border border-gray-200 p-5 mt-4">
        {done ? (
          <div className="text-center py-2">
            <div className="text-3xl mb-1">🎆</div>
            <h2 className="text-base font-bold text-gray-900">Thank you!</h2>
            <p className="text-sm text-gray-500 mt-1">Your feedback helps us serve you better.</p>
          </div>
        ) : (
          <>
            <h2 className="text-base font-bold text-gray-900 mb-1">How was your experience?</h2>
            <div className="flex justify-center gap-1.5 my-3">
              {[1, 2, 3, 4, 5].map((n) => (
                <button key={n} type="button" onClick={() => setRating(n)}
                  onMouseEnter={() => setHover(n)} onMouseLeave={() => setHover(0)} className="p-1">
                  <Star className={`w-9 h-9 ${(hover || rating) >= n ? "fill-amber-400 text-amber-400" : "text-gray-300"}`} />
                </button>
              ))}
            </div>
            <textarea value={comment} onChange={(e) => setComment(e.target.value)} rows={3} placeholder="Tell us more (optional)"
              className="w-full px-3 py-2.5 rounded-xl border border-gray-200 text-sm text-gray-900 focus:outline-none focus:border-orange-400" />
            {err && <p className="text-red-600 text-sm mt-2">{err}</p>}
            <button onClick={submit} disabled={busy}
              className="w-full mt-3 py-3 rounded-xl bg-orange-500 hover:bg-orange-600 text-white font-semibold disabled:opacity-60">
              {busy ? "Submitting…" : "Submit feedback"}
            </button>
          </>
        )}
      </div>
    </Card>
  );
}

